import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';
import { Users } from 'lucide-react';
import './PartnerBuyers.css';

function PartnerBuyers() {
  const [buyers, setBuyers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    loadBuyers();
  }, []);

  const loadBuyers = async () => {
    try {
      setLoading(true);
      const response = await partnerService.getBuyers();
      setBuyers(response.data);
      setError('');
    } catch (err) {
      console.error('Load buyers error:', err);
      setError('Failed to load buyers');
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    return `₹${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-IN', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  if (loading) {
    return <div className="loading">Loading buyers...</div>;
  }

  return (
    <div className="partner-buyers-page">
      <div className="page-header">
        <div>
          <h1>My Buyers</h1>
          <p>Customers who have purchased through you</p>
        </div>
      </div>

      {error && <div className="error-message">{error}</div>}

      {buyers.length === 0 ? (
        <div className="empty-state">
          <Users size={64} color="#ccc" />
          <h3>No Buyers Yet</h3>
          <p>You haven't made any sales yet. Buyers will appear here after your first sale.</p>
        </div>
      ) : (
        <div className="table-container">
          <table className="data-table">
            <thead>
              <tr>
                <th>Buyer Name</th>
                <th>Email</th>
                <th>Company</th>
                <th>Phone</th>
                <th>Total Purchases</th>
                <th>Total Spent</th>
                <th>Last Purchase</th>
              </tr>
            </thead>
            <tbody>
              {buyers.map((buyer) => (
                <tr key={buyer.userId}>
                  <td className="buyer-name">{buyer.fullName}</td>
                  <td className="buyer-email">{buyer.email}</td>
                  <td>{buyer.companyName || '-'}</td>
                  <td>{buyer.phoneNumber || '-'}</td>
                  <td className="text-center">{buyer.totalPurchases}</td>
                  <td className="amount">{formatCurrency(buyer.totalSpent)}</td>
                  <td>{formatDate(buyer.lastPurchase)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default PartnerBuyers;
